import re

def extract_one_liner(line):
    """Extract or create a one-liner summary from a multi-line entry."""
    # Pattern: - `Name` (path) — closed iter-NNN: <narrative>
    match = re.match(r'- `([^`]+)` \(([^)]+)\) — closed iter-(\d+): (.+)', line)
    if not match:
        return None

    name, path, iter_num, narrative = match.groups()

    # Extract key techniques and gaps from the narrative
    # Look for patterns like "Mathlib gap-fill", "kernel-only", technique names
    narrative = narrative.strip()

    # If it's already a single short line, keep it
    if len(narrative) < 100 and ';' not in narrative and '\n' not in narrative:
        return line  # Already short enough

    # Extract technique and any Mathlib reference
    # Common patterns: "X; kernel-only", "technique via Y", "Mathlib gap-fill: X"
    technique = narrative.split(';')[0].strip()

    # Check for Mathlib gaps
    has_mathlib_gap = 'Mathlib gap-fill' in line or 'Mathlib gap' in narrative
    mathlib_ref = ''
    if has_mathlib_gap:
        mathlib_match = re.search(r'Mathlib gap[^;]*', narrative)
        if mathlib_match:
            mathlib_ref = f"; {mathlib_match.group(0).strip()}"

    # Check for kernel-only or other annotations
    annotation = ''
    if 'kernel-only' in narrative:
        annotation = '; kernel-only'
    elif 'axiom-checked' in narrative:
        annotation = '; axiom-checked'
    elif 'compilation verified' in narrative:
        annotation = '; compilation verified'

    # Build compressed one-liner
    compressed = f"- `{name}` ({path}) — closed iter-{iter_num}: {technique}{mathlib_ref}{annotation}."

    return compressed

# Read the file
with open('/tmp/task_done_full.md', 'r') as f:
    lines = f.readlines()

# Process and rewrite
header = []
entries_section = []
max_iter = 79
threshold_iter = max_iter - 4  # 75

header_done = False
current_entry = []

for line in lines:
    if not header_done and not line.startswith('- `') and line.strip() and 'NOT closed' not in line and '**Structural' not in line:
        header.append(line)
    elif not header_done and line.startswith('- `'):
        header_done = True
        # Process first entry
        match = re.search(r'closed iter-(\d+)', line)
        if match:
            iter_num = int(match.group(1))
            if iter_num <= threshold_iter:
                compressed = extract_one_liner(line.rstrip('\n'))
                if compressed:
                    entries_section.append(compressed + '\n')
                else:
                    entries_section.append(line)
            else:
                entries_section.append(line)
        else:
            entries_section.append(line)
    elif header_done:
        # Check if it's a new entry or continuation
        if line.startswith('- `'):
            match = re.search(r'closed iter-(\d+)', line)
            if match:
                iter_num = int(match.group(1))
                if iter_num <= threshold_iter:
                    compressed = extract_one_liner(line.rstrip('\n'))
                    if compressed:
                        entries_section.append(compressed + '\n')
                    else:
                        entries_section.append(line)
                else:
                    entries_section.append(line)
            else:
                # Special entries like "NOT closed" or structural milestones
                entries_section.append(line)
        else:
            # Continuation or empty line - only keep if it's important
            if line.strip() and '**Structural' in line:
                entries_section.append(line)
            elif line.strip() and 'Caveat' in line:
                entries_section.append(line)
            elif line.strip() and 'Note' in line:
                entries_section.append(line)
            elif line.strip() == '':
                # Empty lines are OK
                entries_section.append(line)
            else:
                # Skip other continuation lines if compressing
                pass

# Write back
output = ''.join(header) + ''.join(entries_section)
with open('/tmp/task_done_compressed.md', 'w') as f:
    f.write(output)

print("Compression complete!")
print(f"Original size: {len(open('/tmp/task_done_full.md').read())} chars")
print(f"Compressed size: {len(output)} chars")
print(f"Compression ratio: {100 * len(output) / len(open('/tmp/task_done_full.md').read()):.1f}%")

# Show first few compressed entries
print("\nFirst 5 compressed entries:")
for line in output.split('\n')[3:8]:
    if line.startswith('- `'):
        print(f"  {line[:120]}...")

